SELECT COUNT(*) AS fixed_bugs_count
FROM bug_fixes
WHERE fixed_by = 1;

SELECT type_name
FROM bug_types
WHERE category = 'security';

SELECT COUNT(workaround_id) AS workaround_count
FROM bug_workarounds
WHERE created_by = 1;

SELECT COUNT(*) AS open_bug_count
FROM bugs
WHERE status = 'open';

SELECT COUNT(*) AS access_count
FROM bug_access
WHERE bug_id = 1;

SELECT description
FROM bugs
WHERE bug_id = 1;

SELECT u.user_name
FROM users u
INNER JOIN project_managers pm ON u.user_id = pm.user_id;

SELECT status, COUNT(bug_id) AS bug_count, MAX(date_fixed) AS latest_fix_date
FROM bugs
GROUP BY status;
